/**
 * Typed wrapper around the dashboard backend API.
 *
 * The dashboard SPA only ever talks to its own service (`/api/...`),
 * which in turn proxies to workspace/gateway/identity over loopback.
 * This keeps CORS out of the picture in both Compose mode and Embedded
 * mode.
 */

const baseUrl = "/api";

export interface TenantBootstrapRequest {
  tenant_name: string;
  llm_keys?: Partial<{
    anthropic: string;
    openai: string;
  }>;
  mock_mode?: boolean;
}

export interface TenantBootstrapResponse {
  tenant_id: string;
  api_key: string;
  dashboard_url: string;
}

export interface TenantSummary {
  count: number;
}

class ApiError extends Error {
  constructor(
    message: string,
    public readonly status: number,
    public readonly remediation?: string,
  ) {
    super(message);
    this.name = "ApiError";
  }
}

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const resp = await fetch(`${baseUrl}${path}`, {
    headers: {
      "content-type": "application/json",
      ...(init?.headers ?? {}),
    },
    ...init,
  });

  if (!resp.ok) {
    const body = (await resp.json().catch(() => ({}))) as {
      detail?: string;
      remediation?: string;
    };
    throw new ApiError(
      body.detail ?? `${resp.status} ${resp.statusText}`,
      resp.status,
      body.remediation,
    );
  }
  return (await resp.json()) as T;
}

export const api = {
  /** Lists tenants. Used by the dashboard root to decide whether to redirect to /welcome. */
  tenantSummary: () => request<TenantSummary>("/identity/tenants/summary"),

  /**
   * Idempotent first-run bootstrap. POSTs once on wizard "Start" click.
   * 409 if a tenant already exists — wizard catches and redirects to /.
   */
  bootstrap: (payload: TenantBootstrapRequest) =>
    request<TenantBootstrapResponse>("/identity/bootstrap", {
      method: "POST",
      body: JSON.stringify(payload),
    }),
};

export { ApiError };
